create table dirkspzm32.isi_adressen (
    sid                          varchar2(2 char) default '01' not null enable,
    adress_id                    number(*, 0) not null enable,
    firma_nr                     number(2, 0) default 1 not null enable,
    adr_art                      varchar2(1 char) not null enable,
    adr_nr                       varchar2(20 char) not null enable,
    adr_liefer                   varchar2(20 char) not null enable,
    name_1                       varchar2(40 char),
    name_2                       varchar2(40 char),
    name_3                       varchar2(40 char),
    plz                          varchar2(20 char),
    ort                          varchar2(40 char),
    aktiv                        varchar2(1 char) default 'T' not null enable,
    anspr                        varchar2(40 char),
    email                        varchar2(40 char),
    tel                          varchar2(40 char),
    fax                          varchar2(40 char),
    lte_etiketten_name           varchar2(50 char),
    lhm_etiketten_name           varchar2(50 char),
    strasse                      varchar2(40 char),
    ext_etiketten_druck          varchar2(1 char) default 'F' not null enable,
    charge_lte_id_lief_tausch    varchar2(1 char) default 'F' not null enable,
    isiplus_module               varchar2(255 char),
    lte_etiketten_typ            varchar2(50 char),
    lte_etiketten_spez_barcode   varchar2(50 char),
    lhm_etiketten_typ            varchar2(50 char),
    lhm_etiketten_spez_barcode   varchar2(50 char),
    land                         varchar2(40 char),
    land_kurz                    varchar2(10 char),
    info_1                       varchar2(100 char),
    lhm_etiketten_layout         varchar2(30 char),
    lte_etiketten_layout         varchar2(30 char),
    ecc_hersteller_id            varchar2(10 char),
    edi_gln                      varchar2(35 char),
    edi_gln_b                    varchar2(35 char),
    adress_id_h                  number(*, 0),
    edi_gln_r                    varchar2(35 char),
    edi_enabled                  varchar2(1 char) default 'F' not null enable,
    avis                         varchar2(10 char),
    waehrung                     varchar2(5 char),
    kundennrlief                 varchar2(20 char),
    lief_eink_rabatt_faktor      number(*, 5),
    eink_preis_berechnen         varchar2(1 char) default 'F',
    lieferbedingungen            varchar2(500 char),
    zahlungsbedingungen          varchar2(500 char),
    ust_id_nummer                varchar2(20 char),
    rg_mwst_text                 varchar2(500 char),
    lte_lhm_nummernkreis_von     number(*, 5),
    lte_lhm_nummernkreis_bis     number(*, 5),
    lte_lhm_nummernkreis_aktuell number(*, 5),
    lte_barcode_type             varchar2(10 char),
    lte_eigener_nr_kreis         varchar2(1 char),
    lte_barcode_kopf             varchar2(20 char),
    lte_barcode_laenge           number(2, 0),
    lhm_barcode_type             varchar2(10 char),
    lhm_eigener_nr_kreis         varchar2(1 char),
    lhm_barcode_kopf             varchar2(20 char),
    lhm_barcode_laenge           number(2, 0),
    zollpflicht                  varchar2(1 char) default 'F',
    region_code                  varchar2(40 char)
);

alter table dirkspzm32.isi_adressen
    add constraint pk_isi_adressen primary key ( adress_id )
        using index enable;

alter table dirkspzm32.isi_adressen
    add constraint uix_isi_adr_kd_adr_lief_adr
        unique ( adr_nr,
                 adr_liefer,
                 adr_art )
            using index enable;


